final:
module top_module(
    input in1,
    input in2,
    input en,
    output out
);reg out_reg;
  wire _tap_in1 = in1 & {1{1'b1}};


always @(*) begin
    if (en == 1'b0) begin
        out_reg = 1'b0;
    end else begin
        out_reg = ~(in1 | in2);
    end
end

assign out = out_reg;

endmodule
